public int maxSumAfterKOperations(int[] nums, int k) {
    PriorityQueue<Integer> pq = new PriorityQueue<>();
    for(int num : nums) pq.add(num);
    while(k-- > 0){
        int current = pq.poll();
        pq.add(-current);
    }
    int sum = 0;
    for(int num : pq) sum += num;
    return sum;
}
